(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[2029],{2553:(n,e,a)=>{"use strict";a.r(e),a.d(e,{data:()=>t});const t={key:"v-682bd271",path:"/python/intro/install/",title:"เริ่มต้นใช้งานภาษา Python",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"ติดตั้ง Python",slug:"ติดตั้ง-python",children:[{level:3,title:"จาก Python.org (แนะนำ)",slug:"จาก-python-org-แนะนํา",children:[]},{level:3,title:"จาก Anaconda.com",slug:"จาก-anaconda-com",children:[]},{level:3,title:"ด้วย HomeBrew (สำหรับ macOS)",slug:"ด้วย-homebrew-สําหรับ-macos",children:[]}]},{level:2,title:"ทดสอบว่ามี Python อยู่ในเครื่องแล้ว",slug:"ทดสอบว่ามี-python-อยู่ในเครื่องแล้ว",children:[]},{level:2,title:"ใช้งานภาษา Python",slug:"ใช้งานภาษา-python",children:[{level:3,title:"Using Python Shell and Editor on IDLE",slug:"using-python-shell-and-editor-on-idle",children:[]},{level:3,title:"Using Python Shell on Terminal",slug:"using-python-shell-on-terminal",children:[]}]}],filePathRelative:"python/intro/install/README.md",git:{updatedTime:162676698e4,contributors:[]}}},1769:(n,e,a)=>{"use strict";a.r(e),a.d(e,{default:()=>r});var t=a(6252);const o=(0,t.uE)('<h1 id="เริ่มต้นใช้งานภาษา-python" tabindex="-1"><a class="header-anchor" href="#เริ่มต้นใช้งานภาษา-python" aria-hidden="true">#</a> เริ่มต้นใช้งานภาษา Python</h1><p>ก่อนที่เราจะสามารถรันโค้ด Python ได้ เครื่องที่เราต้องการพัฒนาโค้ดก็จำเป็นจะต้องติดตั้ง Python เสียก่อน โดยมีวิธีดังนี้ครับ</p><h2 id="ติดตั้ง-python" tabindex="-1"><a class="header-anchor" href="#ติดตั้ง-python" aria-hidden="true">#</a> ติดตั้ง Python</h2><p>เรามีวิธีให้เลือกเพื่อติดตั้ง Python บนอุปกรณ์ดังนี้ครับ</p><ul><li>Install มาจาก Python.org</li><li>Install ด้วย Conda</li><li>Install โดยการใช้ HomeBrew (สำหรับ macOS)</li><li>Install โดยการใช้ apt-get (สำหรับ Linux-based OS)</li></ul><h3 id="จาก-python-org-แนะนํา" tabindex="-1"><a class="header-anchor" href="#จาก-python-org-แนะนํา" aria-hidden="true">#</a> จาก Python.org (แนะนำ)</h3>',6),s=(0,t.Uk)("น้องๆสามารถดาวน์โหลดตัว Python + Python IDE (IDLE) ที่เว็บไซต์ของ Python.org ได้จากลิงก์นี้เลยครับ "),l={href:"https://www.python.org/downloads/",target:"_blank",rel:"noopener noreferrer"},i=(0,t.Uk)("https://www.python.org/downloads/"),h=(0,t.uE)('<p>โดยให้น้องดาวน์โหลดเวอร์ชันล่าสุด โดยเวอร์ชั่นล่าสุดจะปุ่มสีเหลืองตามภาพก็ให้กดเพื่อดาวน์โหลด Python ลงเครื่องของน้องๆครับ</p><figure><img src="pythonDotOrg.png"><figcaption>หน้าเว็บไซต์ Python.org</figcaption></figure><p>แล้วก็ทำการ Install เข้าเครื่องครับ และหากว่าเสร็จแล้วก็จะเห็นว่ามีโปรแกรมที่ชื่อว่า Python และ IDE เริ่มต้นติดเครื่องอย่าง IDLE เอาไว้ให้อุ่นใจ</p><h3 id="จาก-anaconda-com" tabindex="-1"><a class="header-anchor" href="#จาก-anaconda-com" aria-hidden="true">#</a> จาก Anaconda.com</h3><p>น้องๆ สามารถดาวน์โหลด Python ได้จากทาง Anaconda ครับ</p><p>ข้อดีอย่างนึงของการทำแบบนี้นั่นคือ Conda (เป็นตัวจัดการ Python ของ Anacoda) จะทำการอับเดทเวอร์ชันให้น้องๆ ให้เป็นเวอร์ชั่นล่าสุดอย่างอัตโนมัติครับ ไม่จำเป็นที่จะต้องไปลงใหม่เหมือนกับวิธีแรก</p><p>แต่ข้อเสียจะอยู่ที่ว่ามันไม่มี IDLE ให้อ่ะสิครับ พี่มงเลยแนะนำว่าให้โหลดถ้าน้องๆจะเอาไปใช้กับการเรียน Data Analysis หรือต้องการจะไปเป็น Data Scientist ครับ เพราะว่า tools เค้าพร้อมจริงๆ และใช้งานง่ายด้วย</p><h3 id="ด้วย-homebrew-สําหรับ-macos" tabindex="-1"><a class="header-anchor" href="#ด้วย-homebrew-สําหรับ-macos" aria-hidden="true">#</a> ด้วย HomeBrew (สำหรับ macOS)</h3><p>หรือสำหรับน้องๆที่อยากท้าทายตัวเอง และอยากใช้ Python บน command line ก็สามารถใช้ Homebrew ในการจัดการหลายๆอย่างให้น้องครับ ดีงามโคตรๆ</p><p>หากน้องยังไม่มี Homebrew บนเครื่อง ก็ให้พิพม์บรรทัดด้านล่างไปด้วยนะครับ</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>/usr/bin/ruby -e <span class="token string">&quot;<span class="token variable"><span class="token variable">$(</span><span class="token function">curl</span> -fsSL https://raw.githubusercontent.com/Homebrew/install/master/install<span class="token variable">)</span></span>&quot;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>และทำการพืิมพ์คำสั่งพวกนี้หลังจากทำการติดตั้ง HomeBrew เรียบร้อยแล้ว</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>brew doctor\nbrew <span class="token function">install</span> python\nbrew doctor\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="ทดสอบว่ามี-python-อยู่ในเครื่องแล้ว" tabindex="-1"><a class="header-anchor" href="#ทดสอบว่ามี-python-อยู่ในเครื่องแล้ว" aria-hidden="true">#</a> ทดสอบว่ามี Python อยู่ในเครื่องแล้ว</h2><p>สำหรับน้องที่ใช้ MacOS หรือ Linux Distributions ทั้งหลาย น้องสามารถเช็คว่ามี Python ในเครื่องแล้วหรือยัง โดยการพิมพ์</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>python3\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>ผ่านทาง Terminal ครับ</p><p>และสำหรับน้องๆที่ใช้ Windows ถ้าเห็น IDLE อยู่บน desktop (หรือที่น้องเก็บมันไว้) ก็ถือว่าดาวน์โหลดเรียบร้อยแล้วครับ โดยปกติแล้วจะมีเขียนเวอร์ขั่นของ Python กำกับที่บน IDLE ด้วยครับ (เช่น IDLE 3.6.2)</p><h2 id="ใช้งานภาษา-python" tabindex="-1"><a class="header-anchor" href="#ใช้งานภาษา-python" aria-hidden="true">#</a> ใช้งานภาษา Python</h2><h3 id="using-python-shell-and-editor-on-idle" tabindex="-1"><a class="header-anchor" href="#using-python-shell-and-editor-on-idle" aria-hidden="true">#</a> Using Python Shell and Editor on IDLE</h3><p>IDLE คือ IDE (Integrated Development Environment) ของ Python เอง ซึ่งมันก็จะแตกต่างกับตัว Text Editor อื่นๆ (เช่น Atom, Sublime Text, VS Code) นั่นก็คือมันใช้งานง่ายกว่า และก็สามารถกด <code>F5</code> (สำหรับน้องๆที่ใช้ Windows) เพื่อทำการรันโปรแกรมได้เลย หรือกดปุ่มบนคีย์บอร์ดเพื่อรันโปรแกรม (script) ที่น้องเขียนได้เลย</p><p>โดยเปิดตัว IDLE ขึ้นมาแล้ว น้องๆก็จะเห็นหน้าต่างที่หน้าตาคล้ายๆ command line / shell ของ Python ตามภาพ</p><p><img src="https://images.duckduckgo.com/iu/?u=http%3A%2F%2Fi.stack.imgur.com%2Fbz1qE.jpg&amp;f=1" alt=""><br> หน้าต่าง IDLE</p><div class="custom-container warning"><p class="custom-container-title">คำแนะนำ</p><p>สำหรับน้องๆที่โหลด Python โดยการใช้ วิธีอื่นนอกจากวิธีแรก น้องๆอาจจะไปทำเหมือนวิธีที่ 1 แต่ดาวน์โหลดเพียง IDLE หรือลอง Google ดูครับว่ามีวิธีดาวน์โหลดผ่าน <code>apt-get</code> หรือไม่</p></div><h3 id="using-python-shell-on-terminal" tabindex="-1"><a class="header-anchor" href="#using-python-shell-on-terminal" aria-hidden="true">#</a> Using Python Shell on Terminal</h3><p>สำหรับน้องที่ดาวน์โหลด Python มาโดยการใช้ Homebrew หรือมีบนเครื่องแล้ว ตัว Python บน Terminal ก็สามารถเรียกได้โดยการพิมพ์</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>python3\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>และหน้าจอของน้องๆก็จะเป็นดังภาพ</p><p>หรือน้องๆที่ใช้ Windows ก็สามารถเขียนภาษา Python โดยใช้ shell ได้เหมือนกัน โดยการกดเข้าโปรแกรม Python Shell ก็จะได้ผลลัพท์เช่นเดียวกัน</p><p><img src="https://images.duckduckgo.com/iu/?u=https%3A%2F%2Fraphaelmarques.files.wordpress.com%2F2010%2F03%2Fterminal-python.png&amp;f=1" alt=""></p>',30),r={render:function(n,e){const a=(0,t.up)("OutboundLink");return(0,t.wg)(),(0,t.j4)(t.HY,null,[o,(0,t.Wm)("p",null,[s,(0,t.Wm)("a",l,[i,(0,t.Wm)(a)])]),h],64)}}}}]);